// Aggregate all downloaded images into a single item with multiple binary fields
const folderName = $('New product folder added').item.json.name;
const folderId = $('New product folder added').item.json.id;

const out = {
  json: {
    folderId: folderId,
    folderName: folderName,
  },
  binary: {}
};

const items = $input.all();
items.forEach((item, idx) => {
  if (item.binary && item.binary.data) {
    out.binary[`image${idx + 1}`] = item.binary.data;
  }
});

return [out];

const root = $json;

let text =
  root?.[0]?.content?.find(c => c.type === 'output_text')?.text
  || root?.[0]?.content?.[0]?.text
  || root?.[0]?.[0]?.content?.find(c => c.type === 'output_text')?.text
  || root?.[0]?.[0]?.content?.[0]?.text
  || '';

if (!text) {
  return [{ json: { error: 'No text field found in response', raw: root } }];
}

const lines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean);

const data = {};
for (const line of lines) {
  const eq = line.indexOf('=');
  if (eq === -1) continue;
  const key = line.slice(0, eq).trim();
  const value = line.slice(eq + 1).trim();
  data[key] = value;
}

const featuresBenefits = (data.FEATURES_BENEFITS || '')
  .split('|')
  .map(s => s.trim())
  .filter(Boolean)
  .join('\n');

return [{
  json: {
    nazwa_produktu: data.PRODUCT_NAME || '',
    firma: data.BRAND || '',
    krotki_opis: data.SHORT_DESCRIPTION || '',
    cechy_korzysci: featuresBenefits,
    kod_ean: data.EAN || '',
  }
}];
